example.code:
# Simple alias: flag additions and substitutions
alias gs="git status -sb"
alias ll="ls -alF --color=auto"
alias grep="grep --color=auto"

# Function alias: needs a parameter
mkcd() { mkdir -p "$1" && cd "$1"; }

# Function alias: multi-step
port() { sudo lsof -i ":${1}" 2>/dev/null || echo "Nothing on port $1"; }

# Function alias: needs conditional logic
extract() {
    [ -f "$1" ] || { echo "'$1' is not a file"; return 1; }
    case "$1" in
        *.tar.gz)  tar xzf "$1" ;;
        *.tar.bz2) tar xjf "$1" ;;
        *.zip)     unzip "$1" ;;
        *.gz)      gunzip "$1" ;;
        *)         echo "Unknown archive format: $1" ;;
    esac
}

# Correct: quoted value, safe shadow of rm alias rm="rm -i" # To call original rm without confirmation: \rm file or command rm file
# Correct: reload alias defined early in the file so it is available alias reload="source ~/.bash_aliases && source ~/.bashrc" alias ea="vim ~/.bash_aliases && source ~/.bash_aliases"
# Correct: function for any multi-step logic sysinfo() { echo "Uptime: $(uptime -p)" echo "Memory: $(free -h | awk '/Mem:/{print $3 "/" $2}')" echo "Disk: $(df -h / | awk 'NR==2{print $3 "/" $2 " (" $5 ")"}')" }
